export const SNIPPETS: Record<string, string> = {
  "alloc.h": "/* mtoc runtime helper: malloc wrapper that aborts on allocation\n * failure with a clear diagnostic. Used for every tensor backing\n * buffer (mtoc allocates tensor storage uniformly on the heap so the\n * codegen path is exercised by every test, not just large ones).\n *\n * `n_bytes` is the size in bytes; the call site computes\n * `numel * sizeof(double)`. Returns a non-NULL pointer or aborts.\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic double *mtoc2_alloc(size_t n_bytes) {\n  /* `malloc(0)` is implementation-defined: glibc returns a non-NULL\n   * sentinel, but some C libraries return NULL — which would trip\n   * the OOM abort below on a perfectly valid empty-tensor request.\n   * Clamp to a 1-byte allocation so the contract \"return non-NULL or\n   * abort on OOM\" holds uniformly. The caller never reads from a\n   * zero-element buffer, so the wasted byte is irrelevant. */\n  double *p = (double *)malloc(n_bytes == 0 ? 1 : n_bytes);\n  if (!p) {\n    fprintf(stderr, \"mtoc2: out of memory (mtoc2_alloc requested %zu bytes)\\n\",\n            n_bytes);\n    abort();\n  }\n  return p;\n}\n",
  "disp_double.h": "/* mtoc runtime helper: disp(x) for a real-scalar double.\n *\n * Mirrors numbl's `formatNumber` (numbl/src/numbl-core/runtime/display.ts)\n * so cross-runner test output matches. The actual formatting lives in\n * `format_double.h`; this snippet only wraps it with a print + newline.\n */\n\n#include <stdio.h>\n\nstatic void mtoc2_disp_double(double x) {\n  char buf[64];\n  mtoc2_format_double(buf, sizeof(buf), x);\n  printf(\"%s\\n\", buf);\n}\n",
  "disp_tensor.h": "/* mtoc runtime helper: disp(t) for a multi-element real tensor.\n *\n * Mirrors numbl's `format2DSlice` for the 2-D path and numbl's\n * page-by-page N-D rendering for `ndim > 2` (each 2-D slice prefixed\n * by a `(:,:,k2,k3,...) =` header and separated by a blank line):\n *   - elements are formatted via mtoc2_format_double\n *   - each column is padded to its widest element via padStart\n *   - rows are separated by '\\n', columns by 3 spaces, 3-space indent\n *\n * Allocation: per-slice malloc for the formatted-string buffer and\n * column-width array. Both freed before the next slice. The disp\n * path is not on the hot path of typical numerical code, so the\n * simplicity is worth the alloc.\n *\n * Real-only — complex-tensor disp lives in `disp_tensor_complex.h`;\n * the lowerer dispatches on `isComplex`.\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n\n/* Render a single 2-D slice (rows × cols) starting at `data` (the\n * caller already advanced past prior pages). Each row ends with\n * '\\n'; no leading or trailing framing — the caller adds page\n * headers / separators. */\nstatic void mtoc2__disp_real_slice(const double *data, long rows, long cols) {\n  enum { CELL_CAP = 32 };\n  long ncells = rows * cols;\n  char *cells = (char *)malloc((size_t)ncells * CELL_CAP);\n  long *col_widths = (long *)calloc((size_t)cols, sizeof(long));\n  if (!cells || !col_widths) {\n    free(cells);\n    free(col_widths);\n    fprintf(stderr, \"mtoc2: out of memory in mtoc2_disp_tensor\\n\");\n    return;\n  }\n\n  for (long c = 0; c < cols; c++) {\n    for (long r = 0; r < rows; r++) {\n      long idx = r + c * rows;\n      char *cell = cells + idx * CELL_CAP;\n      mtoc2_format_double(cell, CELL_CAP, data[idx]);\n      long len = (long)strlen(cell);\n      if (len > col_widths[c]) col_widths[c] = len;\n    }\n  }\n\n  for (long r = 0; r < rows; r++) {\n    fputs(\"   \", stdout);\n    for (long c = 0; c < cols; c++) {\n      long idx = r + c * rows;\n      char *cell = cells + idx * CELL_CAP;\n      long len = (long)strlen(cell);\n      for (long i = 0; i < col_widths[c] - len; i++) putchar(' ');\n      fputs(cell, stdout);\n      if (c < cols - 1) fputs(\"   \", stdout);\n    }\n    putchar('\\n');\n  }\n\n  free(cells);\n  free(col_widths);\n}\n\nstatic void mtoc2_disp_tensor(mtoc2_tensor_t t) {\n  long rows = t.ndim >= 1 ? t.dims[0] : 1;\n  long cols = t.ndim >= 2 ? t.dims[1] : 1;\n  if (rows <= 0 || cols <= 0) {\n    /* Empty tensor — match numbl's \"[]\" rendering. */\n    printf(\"[]\\n\");\n    return;\n  }\n  long page_size = rows * cols;\n  long num_pages = 1;\n  for (int i = 2; i < t.ndim; i++) num_pages *= t.dims[i];\n\n  for (long p = 0; p < num_pages; p++) {\n    if (t.ndim > 2) {\n      /* Blank line between pages (after the previous slice's trailing\n       * '\\n'). For the very first page there is no leading separator. */\n      if (p > 0) putchar('\\n');\n      /* Outer indices via column-major ind2sub (k2 changes fastest). */\n      long rem = p;\n      fputs(\"(:,:\", stdout);\n      for (int i = 2; i < t.ndim; i++) {\n        long d = t.dims[i];\n        long s = rem % d;\n        rem /= d;\n        printf(\",%ld\", s + 1);\n      }\n      fputs(\") =\\n\\n\", stdout);\n    }\n    mtoc2__disp_real_slice(t.real + p * page_size, rows, cols);\n  }\n}\n",
  "format_double.h": "/* mtoc runtime helper: format a double the same way numbl's\n * `formatNumber` does, into a caller-provided buffer.\n *\n * Used by both scalar and tensor disp so cross-runner output matches\n * numbl byte-for-byte. Kept in its own snippet so disp_double.h and\n * disp_tensor.h can pull it in via the snippet dependency mechanism.\n *\n * Returns the number of characters written (excluding trailing NUL).\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n#include <math.h>\n\nstatic int mtoc2_format_double(char *out, size_t cap, double x) {\n  if (isnan(x)) return snprintf(out, cap, \"NaN\");\n  if (isinf(x)) return snprintf(out, cap, x > 0 ? \"Infinity\" : \"-Infinity\");\n  if (x == 0.0) x = 0.0; /* normalize -0 */\n\n  if (fabs(x) < 1e15 && x == (double)(long long)x) {\n    return snprintf(out, cap, \"%lld\", (long long)x);\n  }\n\n  char buf[64];\n  snprintf(buf, sizeof(buf), \"%.4e\", x);\n  char *e_p = strchr(buf, 'e');\n  if (!e_p) return snprintf(out, cap, \"%s\", buf);\n  int dec_exp = atoi(e_p + 1);\n\n  if (dec_exp < -6 || dec_exp >= 5) {\n    /* Scientific. Strip trailing zeros from mantissa, drop leading\n       zeros from the exponent, but keep its sign. */\n    char *m_end = e_p - 1;\n    while (m_end > buf && *m_end == '0') m_end--;\n    if (m_end >= buf && *m_end == '.') m_end--;\n    char *exp_p = e_p + 1;\n    char sign = '+';\n    if (*exp_p == '+' || *exp_p == '-') { sign = *exp_p; exp_p++; }\n    while (*exp_p == '0' && *(exp_p + 1) != '\\0') exp_p++;\n    return snprintf(out, cap, \"%.*se%c%s\",\n                    (int)(m_end - buf + 1), buf, sign, exp_p);\n  }\n\n  int frac_digits = 4 - dec_exp;\n  if (frac_digits < 0) frac_digits = 0;\n  snprintf(buf, sizeof(buf), \"%.*f\", frac_digits, x);\n  if (strchr(buf, '.')) {\n    size_t len = strlen(buf);\n    while (len > 0 && buf[len - 1] == '0') len--;\n    if (len > 0 && buf[len - 1] == '.') len--;\n    buf[len] = '\\0';\n  }\n  return snprintf(out, cap, \"%s\", buf);\n}\n",
  "length.h": "/* mtoc runtime helper: MATLAB's `length(t)` on a multi-element tensor.\n *\n * Returns the size of the largest axis as a double, or 0.0 if any axis\n * has length 0. Mirrors MATLAB/numbl semantics. Scalar args don't reach\n * this helper — codegen emits the literal `1.0` directly because the C\n * arg is a bare `double`, not an `mtoc2_tensor_t`.\n */\n\nstatic double mtoc2_length(mtoc2_tensor_t t) {\n  long max = 0;\n  for (int i = 0; i < t.ndim; i++) {\n    if (t.dims[i] == 0) return 0.0;\n    if (t.dims[i] > max) max = t.dims[i];\n  }\n  return (double)max;\n}\n",
  "loop_count.h": "/* mtoc2 runtime helper: compute the iteration count for a numbl-style\n * `start : step : end` range as a non-negative `long`.\n *\n * Mirrors numbl's `makeRangeTensor` formula\n * (`Math.max(0, Math.floor((end - start) / step + 1 + 1e-10))`) so\n * that float-imprecision ranges like `0:0.1:0.3` produce the same 4\n * elements both runners. The naive `floor((e-s)/step) + 1` would give\n * 3 because `(0.3 - 0) / 0.1` evaluates to 2.99999999..., one ulp\n * below 3. The `+ 1e-10` cushion is small enough that mathematically\n * non-integer quotients still floor down (the cushion only matters\n * within an ulp of an integer).\n *\n * `step == 0` short-circuits to an empty range — division-by-zero on\n * IEEE doubles would give ±Inf, then `floor(±Inf) + 1` is ±Inf, and\n * the `(long)` cast on Inf is undefined. The early return matches\n * numbl, which also treats step == 0 as empty.\n *\n * The same formula appears at every range-emitting codegen site\n * (single-slot slice reads, multi-slot slice setup, slice range writes,\n * MakeRange, and the For loop); routing through one helper centralizes\n * the cast and protects against undefined behavior when `floor(...)`\n * returns a value outside the `long` range.\n *\n * Returns `0` on:\n *   - step == 0\n *   - non-finite floor result (NaN — e.g. start/end NaN)\n *   - empty range (negative count)\n *   - count that doesn't fit in `long` (clamped rather than aborting:\n *     the user gets an empty range, which is the safest fallback\n *     under static translation — a 1e19-iteration loop is almost\n *     certainly a typo).\n */\n\n#include <limits.h>\n#include <math.h>\n\nstatic long mtoc2_loop_count(double start, double end, double step) {\n  if (step == 0.0) return 0;\n  double n = floor((end - start) / step + 1.0 + 1e-10);\n  if (!isfinite(n)) return 0;\n  if (n <= 0.0) return 0;\n  /* `(long)n` is undefined when n > LONG_MAX. Compare in double\n   * space to keep the guard well-defined. */\n  if (n > (double)LONG_MAX) return 0;\n  return (long)n;\n}\n",
  "numel.h": "/* mtoc runtime helper: MATLAB's `numel(t)` on a multi-element tensor.\n *\n * Returns the product of the axis sizes as a double. Scalar args don't\n * reach this helper — codegen emits the literal `1.0` directly because\n * the C arg is a bare `double`, not an `mtoc2_tensor_t`.\n */\n\nstatic double mtoc2_numel(mtoc2_tensor_t t) {\n  long n = 1;\n  for (int i = 0; i < t.ndim; i++) {\n    n *= t.dims[i];\n  }\n  return (double)n;\n}\n",
  "oob.h": "/* mtoc2 runtime helpers: index bounds checks for tensor access.\n *\n * Numbl raises a `RuntimeError(\"Index exceeds array bounds\")` on any\n * out-of-range scalar or slice access; mtoc2 must match — without these\n * checks the emitter would compile to a raw `base.real[off]` access\n * that silently reads/writes past the buffer.\n *\n * Three helpers cover the access shapes:\n *   - `mtoc2_idx_axis`: per-axis check used by 2-arg or N-arg scalar\n *     indexing (`M(i,j)`, `T(i,j,k)`). Catches `M(4, 1)` on a 2x3\n *     matrix where the linear-total check would erroneously pass.\n *   - `mtoc2_idx_lin`: linear-index check used by 1-arg indexing\n *     (`v(i)`). Validates against numel(t).\n *   - `mtoc2_check_axis_range`: closed-interval check for slice\n *     setup. The slice helpers compute `first`/`last` once at setup\n *     time and call this before iterating.\n *\n * Each helper returns the 0-based offset (or 0-based index) on\n * success and aborts via `mtoc2_oob_abort` on failure. The `loc`\n * string is \"<file>:<offset>\" from the index's source span — formatted\n * by the emitter so the user sees the violating access site.\n *\n * `abort()` is the right exit signal: AddressSanitizer-built binaries\n * already abort on heap-buffer-overflow, so mirroring that gives the\n * same exit code (non-zero, surfaced through execFile in the cross-\n * runner). The cross-runner can't compare stdout when one runner errors,\n * so the unit test suite (vitest) is the home for OOB regression\n * coverage; this helper just makes the runtime error deterministic.\n */\n\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic void mtoc2_oob_abort(\n  const char *loc, int axis, long got, long lo, long hi\n) {\n  if (axis < 0) {\n    fprintf(stderr,\n      \"%s: Index exceeds array bounds (got %ld, valid %ld..%ld)\\n\",\n      loc, got, lo, hi);\n  } else {\n    fprintf(stderr,\n      \"%s: Index in position %d exceeds array bounds (got %ld, valid %ld..%ld)\\n\",\n      loc, axis + 1, got, lo, hi);\n  }\n  /* exit(1) rather than abort(): abort raises SIGABRT, which\n   * spawnSync surfaces as `signal` instead of `status`. The CLI\n   * falls through to `process.exit(run.status ?? 0)` and would\n   * report a successful run. exit(1) gives a clean non-zero\n   * status that the cross-runner sees as \"mtoc2 errored\". */\n  exit(1);\n}\n\nstatic long mtoc2_idx_axis(\n  const mtoc2_tensor_t *t, int axis, long got1, const char *loc\n) {\n  long dim = t->dims[axis];\n  if (got1 < 1 || got1 > dim) mtoc2_oob_abort(loc, axis, got1, 1, dim);\n  return got1 - 1;\n}\n\nstatic long mtoc2_idx_lin(\n  const mtoc2_tensor_t *t, long got1, const char *loc\n) {\n  long total = 1;\n  for (int i = 0; i < t->ndim; i++) total *= t->dims[i];\n  if (got1 < 1 || got1 > total) mtoc2_oob_abort(loc, -1, got1, 1, total);\n  return got1 - 1;\n}\n\nstatic void mtoc2_check_axis_range(\n  const mtoc2_tensor_t *t, int axis, long first1, long last1, const char *loc\n) {\n  long dim = t->dims[axis];\n  if (first1 < 1 || first1 > dim) mtoc2_oob_abort(loc, axis, first1, 1, dim);\n  if (last1 < 1 || last1 > dim) mtoc2_oob_abort(loc, axis, last1, 1, dim);\n}\n\n/* Linear (single-slot) range bounds check: validates against\n * `numel(t)` rather than a per-axis dim. Used by `v(a:b)` /\n * `M(a:b)` style single-slot range slices, where MATLAB semantics\n * are linear-flatten regardless of base shape. */\nstatic void mtoc2_check_linear_range(\n  const mtoc2_tensor_t *t, long first1, long last1, const char *loc\n) {\n  long total = 1;\n  for (int i = 0; i < t->ndim; i++) total *= t->dims[i];\n  if (first1 < 1 || first1 > total) mtoc2_oob_abort(loc, -1, first1, 1, total);\n  if (last1 < 1 || last1 > total) mtoc2_oob_abort(loc, -1, last1, 1, total);\n}\n",
  "range_value.h": "/* mtoc2 runtime helper: i-th element of a numbl-style `start:step:end`\n * range, with snap-to-end on the last element.\n *\n * Mirrors numbl's `makeRangeTensor` step-of-i computation:\n *   - element i is `start + step * i`\n *   - the LAST element (i == count - 1) snaps to exactly `end` when\n *     the computed value is within `|step| * 1e-10` of `end`. Without\n *     the snap, ranges like `0.1:0.1:0.3` produce a last element of\n *     `0.3000000000000000444...`, so `v(end) == 0.3` evaluates to\n *     false even though the user wrote `:0.3`.\n *\n * Used by `mtoc2_tensor_make_range`, slice-read range generation, and\n * the For-loop emitter so every range-yielding site agrees on the\n * snapped values numbl produces.\n */\n\n#include <math.h>\n\nstatic double mtoc2_range_value(\n  double start, double step, double end, long count, long i\n) {\n  double v = start + step * (double)i;\n  if (i == count - 1 && fabs(v - end) < fabs(step) * 1e-10) return end;\n  return v;\n}\n",
  "sum.h": "/* mtoc2 runtime helper: sum(t) — reduce a real tensor to a scalar.\n *\n * Walks every element via a single linear loop over the flat buffer.\n * Numbl semantics for the \"reduce to scalar\" case: input is a scalar\n * (degenerate, returns t.real[0]), a vector (1×N or N×1), or any\n * higher-dim shape with at most one non-singleton axis. The lowerer\n * routes statically-known matrix inputs to a different (deferred)\n * path; here we trust the caller's shape gate.\n *\n * Real-only. Complex sum and matrix-to-row reductions come later.\n */\n\nstatic double mtoc2_sum(mtoc2_tensor_t t) {\n  long n = 1;\n  for (int i = 0; i < t.ndim; i++) n *= t.dims[i];\n  double s = 0.0;\n  for (long i = 0; i < n; i++) s += t.real[i];\n  return s;\n}\n",
  "tensor.h": "/* mtoc tensor runtime: the single C representation for every\n * multi-element tensor mtoc emits.\n *\n * Storage mirrors numbl's split layout — `real` and `imag` are\n * separate Float64 buffers (not interleaved real/imag pairs). For a\n * statically-real tensor, `imag` is NULL: the type system tracks\n * `isComplex` at compile time, so codegen knows up front whether to\n * touch the imag side. There is no runtime branch on `imag != NULL`.\n *\n * Scalars never use this struct — real scalars are bare `double`,\n * complex scalars are `double _Complex`. Anything the type system\n * classifies as multi-element (any axis is `notOne`) gets one\n * `mtoc2_tensor_t` value. The data buffers are column-major to match\n * MATLAB / LAPACK.\n *\n * Shape: `ndim` axes with sizes `dims[0..ndim-1]`. The minimum\n * logical ndim is 2 (matching numbl) — a row vector is `{1, n}` and\n * a column vector is `{n, 1}`. `MTOC2_MAX_NDIM` caps the inline dims\n * array; tensors with more axes than that are unrepresentable in\n * mtoc today (the static type system enforces this at lowering).\n * Keeping `dims` inline preserves the value-typed semantics of\n * `mtoc2_tensor_t` — assign / copy / free do a struct copy and\n * touch only the two heap pointers; the shape rides along for free.\n *\n * Storage is heap-allocated via `mtoc2_alloc` at every assignment\n * site. The struct is predeclared with `real = imag = NULL` and\n * `ndim = 0` (no dims populated); the first assignment populates\n * them, and subsequent reassignments at a different runtime shape\n * free the previous buffers and alloc fresh ones. `free` of the\n * predeclared NULLs is a no-op (well-defined by C), so the cleanup\n * path is uniform for first and subsequent assignments alike.\n *\n * The `MTOC2_RESTRICT` qualifier on the buffer pointers tells the\n * compiler that distinct `mtoc2_tensor_t` values' buffers do not\n * alias each other. It expands to `__restrict__` under GCC/Clang\n * and to nothing on compilers that don't recognize it.\n */\n\n#ifndef MTOC2_RESTRICT\n# if defined(__GNUC__) || defined(__clang__)\n#  define MTOC2_RESTRICT __restrict__\n# else\n#  define MTOC2_RESTRICT\n# endif\n#endif\n\n#ifndef MTOC2_MAX_NDIM\n#define MTOC2_MAX_NDIM 8\n#endif\n\ntypedef struct {\n  double *MTOC2_RESTRICT real;   /* always non-NULL */\n  double *MTOC2_RESTRICT imag;   /* NULL iff the tensor is statically real */\n  int  ndim;\n  long dims[MTOC2_MAX_NDIM];\n} mtoc2_tensor_t;\n",
  "tensor_alloc.h": "/* mtoc runtime helper: allocate an uninitialized real tensor of the\n * given shape. Sets `imag = NULL` (the static-real marker). The\n * returned tensor owns its `real` buffer; caller must release via\n * `mtoc2_tensor_free` (or hand it to `mtoc2_tensor_assign`, which takes\n * ownership).\n *\n * `mtoc2_alloc` aborts on OOM, so the returned struct's `real` is\n * always non-NULL. Used by codegen as the workhorse for elementwise-\n * result construction at every multi-element Assign RHS that isn't a\n * plain tensor literal.\n */\n\n#include <stdint.h>\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_alloc(long rows, long cols) {\n  mtoc2_tensor_t out;\n  size_t n;\n#if defined(__has_builtin) && __has_builtin(__builtin_mul_overflow)\n  if (__builtin_mul_overflow((size_t)rows, (size_t)cols, &n)) {\n    fprintf(stderr,\n      \"mtoc2: tensor allocation overflow (%ldx%ld elements)\\n\", rows, cols);\n    abort();\n  }\n#else\n  if ((size_t)cols != 0 && (size_t)rows > (SIZE_MAX / sizeof(double)) / (size_t)cols) {\n    fprintf(stderr,\n      \"mtoc2: tensor allocation overflow (%ldx%ld elements)\\n\", rows, cols);\n    abort();\n  }\n  n = (size_t)rows * (size_t)cols;\n#endif\n  out.real = mtoc2_alloc(n * sizeof(double));\n  out.imag = NULL;\n  out.ndim = 2;\n  out.dims[0] = rows;\n  out.dims[1] = cols;\n  return out;\n}\n",
  "tensor_alloc_nd.h": "/* mtoc2 runtime helper: allocate an uninitialized real tensor with\n * an arbitrary N-D shape.\n *\n * The 2-D fast path lives in `mtoc2_tensor_alloc`; this helper is the\n * variadic N-D sibling that copies `ndim` dim sizes from the caller-\n * supplied `dims` array into the struct.\n *\n * `dims` is consumed read-only — the caller may pass a stack\n * `(long[]){…}` compound literal. The returned tensor owns its\n * `real` buffer; `imag` is NULL (the static-real marker). Aborts\n * on `ndim` exceeding `MTOC2_MAX_NDIM` or on size-math overflow.\n */\n\n#include <stdint.h>\n#include <stdio.h>\n#include <stdlib.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_alloc_nd(int ndim, const long *dims) {\n  if (ndim > MTOC2_MAX_NDIM) {\n    fprintf(stderr,\n      \"mtoc2: tensor ndim %d exceeds MTOC2_MAX_NDIM=%d\\n\", ndim, MTOC2_MAX_NDIM);\n    abort();\n  }\n  mtoc2_tensor_t out;\n  size_t n = 1;\n  for (int i = 0; i < ndim; i++) {\n    out.dims[i] = dims[i];\n    size_t new_n;\n#if defined(__has_builtin) && __has_builtin(__builtin_mul_overflow)\n    if (__builtin_mul_overflow(n, (size_t)dims[i], &new_n)) {\n      fprintf(stderr,\n        \"mtoc2: tensor allocation overflow at dim %d (size %ld)\\n\", i, dims[i]);\n      abort();\n    }\n#else\n    if ((size_t)dims[i] != 0 && n > (SIZE_MAX / sizeof(double)) / (size_t)dims[i]) {\n      fprintf(stderr,\n        \"mtoc2: tensor allocation overflow at dim %d (size %ld)\\n\", i, dims[i]);\n      abort();\n    }\n    new_n = n * (size_t)dims[i];\n#endif\n    n = new_n;\n  }\n  out.ndim = ndim;\n  out.real = mtoc2_alloc(n * sizeof(double));\n  out.imag = NULL;\n  return out;\n}\n",
  "tensor_assign.h": "/* mtoc runtime helper: consume-and-replace tensor assignment.\n *\n * Frees `*lhs`'s current backing buffers and moves `rhs`'s buffers\n * into `*lhs`. The codegen invariant is that every tensor C-expression\n * on an Assign RHS produces a freshly-owned tensor — a literal, a\n * `mtoc2_tensor_copy(...)`, or an elementwise-result built by\n * `mtoc2_tensor_alloc(...)` — so the move (rather than a deep copy\n * here) is sound: there is no caller-side reference to the rhs after\n * the call. After the move `rhs.real`/`rhs.imag` hold the old `*lhs`\n * pointers, but rhs is a temporary in the C sense (it's a value\n * passed by copy) and is discarded immediately.\n *\n * Both frees are unconditional — see `mtoc2_tensor_free` for why\n * that's safe for both real and complex tensors.\n */\n\n#include <stdlib.h>\n\nstatic void mtoc2_tensor_assign(mtoc2_tensor_t *lhs, mtoc2_tensor_t rhs) {\n  free(lhs->real);\n  free(lhs->imag);\n  *lhs = rhs;\n}\n",
  "tensor_copy.h": "/* mtoc runtime helper: deep-copy a real tensor.\n *\n * The returned tensor owns a fresh `real` buffer (memcpy'd from the\n * source); `imag` is NULL since the caller statically knows the\n * source is real. Used by codegen to honor \"copy on every\n * manipulation\" — every tensor-by-name read and every user-function\n * tensor argument is wrapped in this helper, so the receiver always\n * gets an owned tensor.\n */\n\n#include <string.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_copy(mtoc2_tensor_t src) {\n  /* Struct copy preserves ndim and dims; the heap buffer is\n   * replaced with a fresh allocation of the right total size. */\n  mtoc2_tensor_t out = src;\n  long n = 1;\n  for (int i = 0; i < src.ndim; i++) n *= src.dims[i];\n  out.real = mtoc2_alloc((size_t)n * sizeof(double));\n  out.imag = NULL;\n  memcpy(out.real, src.real, (size_t)n * sizeof(double));\n  return out;\n}\n",
  "tensor_elemwise_real.h": "/* mtoc2 runtime helpers: elementwise binary + unary ops on real\n * tensors. Same-shape only (slope-3 first slice) — general broadcast\n * comes later.\n *\n * Convention in the function names:\n *   `_tt` — both args are tensors of the same shape\n *   `_ts` — tensor + scalar (broadcast scalar across all elements)\n *   `_st` — scalar + tensor (only emitted for non-commutative ops)\n *\n * Every helper returns a freshly-owned tensor — the codegen\n * invariant. The caller hands the result to `mtoc2_tensor_assign`\n * (or to a hoisted temp Assign for in-line uses). No shape check\n * here: same-shape requirement is enforced statically at lowering\n * time, so the runtime trusts its inputs.\n */\n\n#include <stdlib.h>\n\n#define MTOC2_DEFINE_ELEMWISE_TT(name, OP)                                  \\\n  static mtoc2_tensor_t name(mtoc2_tensor_t a, mtoc2_tensor_t b) {          \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = a.ndim;                                                        \\\n    for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = a.real[i] OP b.real[i];        \\\n    return r;                                                               \\\n  }\n\n#define MTOC2_DEFINE_ELEMWISE_TS(name, OP)                                  \\\n  static mtoc2_tensor_t name(mtoc2_tensor_t a, double s) {                  \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < a.ndim; i++) n *= a.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = a.ndim;                                                        \\\n    for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = a.real[i] OP s;                \\\n    return r;                                                               \\\n  }\n\n#define MTOC2_DEFINE_ELEMWISE_ST(name, OP)                                  \\\n  static mtoc2_tensor_t name(double s, mtoc2_tensor_t b) {                  \\\n    long n = 1;                                                             \\\n    for (int i = 0; i < b.ndim; i++) n *= b.dims[i];                        \\\n    mtoc2_tensor_t r;                                                       \\\n    r.real = mtoc2_alloc((size_t)n * sizeof(double));                       \\\n    r.imag = NULL;                                                          \\\n    r.ndim = b.ndim;                                                        \\\n    for (int i = 0; i < b.ndim; i++) r.dims[i] = b.dims[i];                 \\\n    for (long i = 0; i < n; i++) r.real[i] = s OP b.real[i];                \\\n    return r;                                                               \\\n  }\n\nMTOC2_DEFINE_ELEMWISE_TT(mtoc2_tensor_plus_tt, +)\nMTOC2_DEFINE_ELEMWISE_TT(mtoc2_tensor_minus_tt, -)\nMTOC2_DEFINE_ELEMWISE_TT(mtoc2_tensor_times_tt, *)\nMTOC2_DEFINE_ELEMWISE_TT(mtoc2_tensor_rdivide_tt, /)\n\nMTOC2_DEFINE_ELEMWISE_TS(mtoc2_tensor_plus_ts, +)\nMTOC2_DEFINE_ELEMWISE_TS(mtoc2_tensor_minus_ts, -)\nMTOC2_DEFINE_ELEMWISE_TS(mtoc2_tensor_times_ts, *)\nMTOC2_DEFINE_ELEMWISE_TS(mtoc2_tensor_rdivide_ts, /)\n\n/* Commutative ops (plus, times) reuse `_ts` for `scalar OP tensor`.\n * Non-commutative ops need their own scalar-first flavor. */\nMTOC2_DEFINE_ELEMWISE_ST(mtoc2_tensor_minus_st, -)\nMTOC2_DEFINE_ELEMWISE_ST(mtoc2_tensor_rdivide_st, /)\n\n/* Unary minus — negate every element. */\nstatic mtoc2_tensor_t mtoc2_tensor_uminus(mtoc2_tensor_t a) {\n  long n = 1;\n  for (int i = 0; i < a.ndim; i++) n *= a.dims[i];\n  mtoc2_tensor_t r;\n  r.real = mtoc2_alloc((size_t)n * sizeof(double));\n  r.imag = NULL;\n  r.ndim = a.ndim;\n  for (int i = 0; i < a.ndim; i++) r.dims[i] = a.dims[i];\n  for (long i = 0; i < n; i++) r.real[i] = -a.real[i];\n  return r;\n}\n",
  "tensor_empty.h": "/* mtoc runtime helper: empty/zero-initialized tensor.\n *\n * Returns the canonical \"no buffers, zero shape\" placeholder used to\n * predeclare every tensor variable. Subsequent assignments overwrite\n * the struct via `mtoc2_tensor_assign`, which frees these (NULL)\n * buffers as a no-op and installs the new value.\n */\n\nstatic mtoc2_tensor_t mtoc2_tensor_empty(void) {\n  mtoc2_tensor_t out = { NULL, NULL, 0, {0} };\n  return out;\n}\n",
  "tensor_free.h": "/* mtoc runtime helper: release a tensor's backing buffers and reset\n * the struct to the empty/zero state.\n *\n * Both `free`s are unconditional. `free(NULL)` is well-defined, so\n * the imag-side free is a no-op for real tensors (where `imag` is\n * always NULL) and a real release for complex tensors. There is no\n * runtime branch on `imag != NULL`. Resetting the struct lets a\n * freed local be safely re-used by `mtoc2_tensor_assign` without\n * leaking. Called at every scope-exit site (end of `main`, end of a\n * function body, every `IRStmt.ReturnFromFunction`).\n */\n\n#include <stdlib.h>\n\nstatic void mtoc2_tensor_free(mtoc2_tensor_t *t) {\n  free(t->real);\n  free(t->imag);\n  t->real = NULL;\n  t->imag = NULL;\n  t->ndim = 0;\n}\n",
  "tensor_from_matrix.h": "/* mtoc runtime helper: build a rows×cols real tensor from a flat\n * column-major data pointer. Codegen reorders the literal's\n * row-major source cells to column-major when it builds the\n * compound-literal array, so layout matches the rest of the runtime.\n */\n\n#include <string.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_from_matrix(\n  const double *data, long rows, long cols\n) {\n  mtoc2_tensor_t out = mtoc2_tensor_alloc(rows, cols);\n  memcpy(out.real, data, (size_t)(rows * cols) * sizeof(double));\n  return out;\n}\n",
  "tensor_from_row.h": "/* mtoc runtime helper: build a 1×n real tensor from a flat data\n * pointer. The caller typically passes a C99 compound literal\n * (`(double[]){1.0, 2.0, 3.0}`), which gives the emitted assignment\n * the same one-line shape as the numbl source.\n */\n\n#include <string.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_from_row(const double *data, long n) {\n  mtoc2_tensor_t out = mtoc2_tensor_alloc(1, n);\n  memcpy(out.real, data, (size_t)n * sizeof(double));\n  return out;\n}\n",
  "tensor_make_range.h": "/* mtoc2 runtime helper: build a freshly-owned 1×N row tensor for a\n * `start : step : end` range used as a value (outside an index slot\n * and outside a for-loop iterable).\n *\n * The count is computed via `mtoc2_loop_count`; the result tensor is\n * allocated via `mtoc2_tensor_alloc_nd` so it lives in the standard\n * owned-tensor lifecycle (assign / copy / free). Caller is expected\n * to consume the result via `mtoc2_tensor_assign(&v, ...)` (or as a\n * fresh function-call arg).\n */\n\nstatic mtoc2_tensor_t mtoc2_tensor_make_range(double start, double step, double end) {\n  long n = mtoc2_loop_count(start, end, step);\n  mtoc2_tensor_t t = mtoc2_tensor_alloc_nd(2, (long[]){1, n});\n  for (long k = 0; k < n; k++) {\n    t.real[k] = mtoc2_range_value(start, step, end, n, k);\n  }\n  return t;\n}\n",
  "tensor_ones_nd.h": "/* mtoc2 runtime helper: build a real N-D tensor filled with ones.\n *\n * Allocates via `mtoc2_tensor_alloc_nd`, then fills the `real` buffer\n * with `1.0` via a plain element loop (`memset` only works for byte\n * patterns; `1.0` is not such a pattern). The returned tensor is\n * freshly owned; `imag` is NULL.\n */\n\nstatic mtoc2_tensor_t mtoc2_tensor_ones_nd(int ndim, const long *dims) {\n  mtoc2_tensor_t out = mtoc2_tensor_alloc_nd(ndim, dims);\n  size_t n = 1;\n  for (int i = 0; i < ndim; i++) n *= (size_t)out.dims[i];\n  for (size_t i = 0; i < n; i++) out.real[i] = 1.0;\n  return out;\n}\n",
  "tensor_zeros_nd.h": "/* mtoc2 runtime helper: build a real N-D tensor filled with zeros.\n *\n * Allocates via `mtoc2_tensor_alloc_nd`, then zero-fills the `real`\n * buffer with `memset`. The returned tensor is freshly owned;\n * `imag` is NULL.\n */\n\n#include <string.h>\n\nstatic mtoc2_tensor_t mtoc2_tensor_zeros_nd(int ndim, const long *dims) {\n  mtoc2_tensor_t out = mtoc2_tensor_alloc_nd(ndim, dims);\n  size_t n = 1;\n  for (int i = 0; i < ndim; i++) n *= (size_t)out.dims[i];\n  memset(out.real, 0, n * sizeof(double));\n  return out;\n}\n",
  "tictoc.h": "/* mtoc2 runtime helper: tic / toc wall-clock timing.\n *\n * State is a single static double holding the most recent tic time\n * (seconds since the CLOCK_MONOTONIC epoch). MATLAB and numbl share\n * this \"one global timer\" semantics — `tic` resets it, `toc` reads\n * the delta. No handle form (`t0 = tic; toc(t0)`) in v1.\n *\n * Wall-clock time uses POSIX clock_gettime(CLOCK_MONOTONIC), which\n * gives nanosecond resolution on Linux and macOS, never goes\n * backwards, and isn't affected by NTP adjustments. Windows is not\n * a target; if it ever becomes one, swap in QueryPerformanceCounter\n * here behind an #ifdef.\n *\n * Output format for the bare-`toc` print form mirrors numbl's\n * `\"Elapsed time is %.6f seconds.\\n\"` exactly so the cross-runner's\n * masking regex (see scripts/run_test_scripts.ts) treats both sides\n * as equivalent.\n */\n\n#include <stdio.h>\n#include <time.h>\n\nstatic double mtoc2_tic_seconds = 0.0;\n\nstatic double mtoc2_now_seconds(void) {\n  struct timespec ts;\n  clock_gettime(CLOCK_MONOTONIC, &ts);\n  return (double)ts.tv_sec + (double)ts.tv_nsec / 1e9;\n}\n\nstatic double mtoc2_tic(void) {\n  mtoc2_tic_seconds = mtoc2_now_seconds();\n  return mtoc2_tic_seconds;\n}\n\nstatic double mtoc2_toc(void) {\n  return mtoc2_now_seconds() - mtoc2_tic_seconds;\n}\n\nstatic void mtoc2_toc_print(void) {\n  double elapsed = mtoc2_toc();\n  printf(\"Elapsed time is %.6f seconds.\\n\", elapsed);\n}\n",
};
